import { useState } from "react";
import axios from "axios";
import { useParams, useNavigate, Link } from "react-router-dom";

function ResetPassword() {
  const { token } = useParams();
  const navigate = useNavigate();

  const [password, setPassword] = useState("");
  const [confirmPassword, setConfirmPassword] = useState("");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [success, setSuccess] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError("");

    if (password.length < 6) {
      setError("Password must be at least 6 characters");
      return;
    }

    if (password !== confirmPassword) {
      setError("Passwords do not match");
      return;
    }

    setLoading(true);

    try {
      await axios.post("http://localhost:8070/api/auth/reset-password", {
        token: token,
        password: password,
        confirmPassword: confirmPassword
      });
      setSuccess(true);
      setTimeout(() => navigate("/login"), 2000);
    } catch (err) {
      setError(err.response?.data?.message || "Failed to reset password");
    } finally {
      setLoading(false);
    }
  };

  if (success) {
    return (
      <div style={{
        minHeight: "100vh",
        background: "linear-gradient(135deg, var(--bg) 0%, var(--bg-hover) 100%)",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        padding: "20px"
      }}>
        <div style={{
          width: "100%",
          maxWidth: "480px",
          backgroundColor: "var(--bg-card)",
          borderRadius: "12px",
          border: "1px solid var(--border)",
          boxShadow: "0 12px 32px rgba(0,0,0,0.08)",
          padding: "48px 40px",
          animation: "slideUp 0.4s ease",
          textAlign: "center"
        }}>
          {/* Success Icon */}
          <div style={{
            width: "64px",
            height: "64px",
            backgroundColor: "#c8e6c9",
            borderRadius: "50%",
            margin: "0 auto 24px",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            fontSize: "32px"
          }}>
            ✓
          </div>

          <h1 style={{
            fontSize: "24px",
            fontWeight: 700,
            color: "var(--text)",
            margin: "0 0 12px 0"
          }}>
            Password Reset
          </h1>

          <p style={{
            fontSize: "14px",
            color: "var(--text-muted)",
            lineHeight: "1.6",
            marginBottom: "24px"
          }}>
            Your password has been successfully reset. You'll be redirected to login shortly.
          </p>

          {/* Back to Login */}
          <Link to="/login" style={{
            display: "inline-block",
            padding: "12px 24px",
            fontSize: "14px",
            fontWeight: 600,
            backgroundColor: "var(--primary)",
            color: "white",
            borderRadius: "8px",
            textDecoration: "none",
            transition: "all 0.2s",
            letterSpacing: "0.3px"
          }}
          onMouseEnter={(e) => {
            e.currentTarget.style.backgroundColor = "var(--primary-hover)";
            e.currentTarget.style.transform = "translateY(-2px)";
            e.currentTarget.style.boxShadow = "0 6px 16px rgba(76, 175, 80, 0.3)";
          }}
          onMouseLeave={(e) => {
            e.currentTarget.style.backgroundColor = "var(--primary)";
            e.currentTarget.style.transform = "translateY(0)";
            e.currentTarget.style.boxShadow = "none";
          }}
          >
            Go to Login
          </Link>
        </div>

        <style>{`
          @keyframes slideUp {
            from {
              opacity: 0;
              transform: translateY(20px);
            }
            to {
              opacity: 1;
              transform: translateY(0);
            }
          }
        `}</style>
      </div>
    );
  }

  return (
    <div style={{
      minHeight: "100vh",
      background: "linear-gradient(135deg, var(--bg) 0%, var(--bg-hover) 100%)",
      display: "flex",
      alignItems: "center",
      justifyContent: "center",
      padding: "20px"
    }}>
      <div style={{
        width: "100%",
        maxWidth: "480px",
        backgroundColor: "var(--bg-card)",
        borderRadius: "12px",
        border: "1px solid var(--border)",
        boxShadow: "0 12px 32px rgba(0,0,0,0.08)",
        padding: "48px 40px",
        animation: "slideUp 0.4s ease"
      }}>
        {/* Header */}
        <div style={{ textAlign: "center", marginBottom: "40px" }}>
          <img src="/logo.svg" alt="Leaf Lanka" style={{
            width: "60px",
            height: "60px",
            objectFit: "contain",
            borderRadius: "8px",
            margin: "0 auto 20px",
            display: "block"
          }} />
          <h1 style={{
            fontSize: "28px",
            fontWeight: 700,
            color: "var(--text)",
            margin: "0 0 8px 0",
            letterSpacing: "-0.5px"
          }}>
            Create New Password
          </h1>
          <p style={{
            fontSize: "14px",
            color: "var(--text-muted)",
            margin: 0
          }}>
            Enter your new password below
          </p>
        </div>

        {/* Error Alert */}
        {error && (
          <div style={{
            padding: "12px 16px",
            backgroundColor: "#ffebee",
            border: "1px solid #ffcdd2",
            borderRadius: "8px",
            marginBottom: "24px",
            color: "#c62828",
            fontSize: "13px",
            fontWeight: 500
          }}>
            {error}
          </div>
        )}

        {/* Form */}
        <form onSubmit={handleSubmit} style={{ display: "flex", flexDirection: "column", gap: "20px" }}>
          {/* Password Field */}
          <div>
            <label style={{
              display: "block",
              fontSize: "13px",
              fontWeight: 600,
              color: "var(--text)",
              marginBottom: "8px",
              textTransform: "uppercase",
              letterSpacing: "0.3px"
            }}>
              New Password
            </label>
            <input
              type="password"
              placeholder="••••••••"
              value={password}
              onChange={(e) => {
                setPassword(e.target.value);
                setError("");
              }}
              required
              style={{
                width: "100%",
                padding: "12px 14px",
                fontSize: "14px",
                border: "1px solid var(--border)",
                borderRadius: "8px",
                backgroundColor: "var(--bg)",
                color: "var(--text)",
                transition: "all 0.2s",
                boxSizing: "border-box",
                outline: "none"
              }}
              onFocus={(e) => {
                e.target.style.borderColor = "var(--primary)";
                e.target.style.boxShadow = "0 0 0 3px var(--primary-soft)";
              }}
              onBlur={(e) => {
                e.target.style.borderColor = "var(--border)";
                e.target.style.boxShadow = "none";
              }}
            />
            <p style={{ fontSize: "12px", color: "var(--text-muted)", marginTop: "6px", margin: "6px 0 0 0" }}>
              Minimum 6 characters
            </p>
          </div>

          {/* Confirm Password Field */}
          <div>
            <label style={{
              display: "block",
              fontSize: "13px",
              fontWeight: 600,
              color: "var(--text)",
              marginBottom: "8px",
              textTransform: "uppercase",
              letterSpacing: "0.3px"
            }}>
              Confirm Password
            </label>
            <input
              type="password"
              placeholder="••••••••"
              value={confirmPassword}
              onChange={(e) => {
                setConfirmPassword(e.target.value);
                setError("");
              }}
              required
              style={{
                width: "100%",
                padding: "12px 14px",
                fontSize: "14px",
                border: "1px solid var(--border)",
                borderRadius: "8px",
                backgroundColor: "var(--bg)",
                color: "var(--text)",
                transition: "all 0.2s",
                boxSizing: "border-box",
                outline: "none"
              }}
              onFocus={(e) => {
                e.target.style.borderColor = "var(--primary)";
                e.target.style.boxShadow = "0 0 0 3px var(--primary-soft)";
              }}
              onBlur={(e) => {
                e.target.style.borderColor = "var(--border)";
                e.target.style.boxShadow = "none";
              }}
            />
          </div>

          {/* Submit Button */}
          <button
            type="submit"
            disabled={loading}
            style={{
              padding: "12px 16px",
              fontSize: "14px",
              fontWeight: 700,
              letterSpacing: "0.3px",
              backgroundColor: loading ? "var(--text-muted)" : "var(--primary)",
              color: "white",
              border: "none",
              borderRadius: "8px",
              cursor: loading ? "not-allowed" : "pointer",
              transition: "all 0.2s",
              marginTop: "8px"
            }}
            onMouseEnter={(e) => {
              if (!loading) {
                e.currentTarget.style.backgroundColor = "var(--primary-hover)";
                e.currentTarget.style.transform = "translateY(-2px)";
                e.currentTarget.style.boxShadow = "0 6px 16px rgba(76, 175, 80, 0.3)";
              }
            }}
            onMouseLeave={(e) => {
              if (!loading) {
                e.currentTarget.style.backgroundColor = "var(--primary)";
                e.currentTarget.style.transform = "translateY(0)";
                e.currentTarget.style.boxShadow = "none";
              }
            }}
          >
            {loading ? "Resetting..." : "Reset Password"}
          </button>
        </form>

        {/* Divider */}
        <div style={{
          height: "1px",
          backgroundColor: "var(--border)",
          margin: "32px 0"
        }} />

        {/* Back to Login */}
        <p style={{
          textAlign: "center",
          fontSize: "14px",
          color: "var(--text-muted)",
          margin: 0
        }}>
          Back to{" "}
          <Link to="/login" style={{
            color: "var(--primary)",
            fontWeight: 600,
            textDecoration: "none",
            transition: "opacity 0.2s"
          }}
          onMouseEnter={(e) => e.currentTarget.style.opacity = "0.8"}
          onMouseLeave={(e) => e.currentTarget.style.opacity = "1"}
          >
            Sign In
          </Link>
        </p>
      </div>

      <style>{`
        @keyframes slideUp {
          from {
            opacity: 0;
            transform: translateY(20px);
          }
          to {
            opacity: 1;
            transform: translateY(0);
          }
        }
      `}</style>
    </div>
  );
}

export default ResetPassword;
